class Solution:
    def numSubarrayBoundedMax(self, nums: List[int], left: int, right: int) -> int:
        def atMost(b):
            ans = j = 0
            for i, x in enumerate(nums):
                if x > b: j = i + 1
                ans += i - j + 1
            return ans
        return atMost(right) - atMost(left - 1)

