class Solution {
public:
    int numSubarrayBoundedMax(vector<int>& nums, int left, int right) {
        auto atMost=[&](int b){
            long long ans=0; int j=0;
            for(int i=0;i<(int)nums.size();i++){
                if(nums[i]>b) j=i+1;
                ans += i-j+1;
            }
            return ans;
        };
        return atMost(right)-atMost(left-1);
    }
};
